queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?category_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCategories ?child ; p:hasFilm_Festivals ?parent . } GROUP BY ?child }
  ?child p:category_name ?category_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Film_Festivals } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?category_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCategories ?child ; p:hasFilm_Festivals ?parent . } GROUP BY ?child }
  ?child p:category_name ?category_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Film_Festivals } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?category_name WHERE {
  ?film_festivals_categories a :Film_Festivals_Categories .
  ?categories a :Categories .
  ?film_festivals_categories p:hasCategories ?categories .
  ?film_festivals a :Film_Festivals .
  ?film_festivals_categories p:hasFilm_Festivals ?film_festivals .
  ?film_festivals p:name ?name .
  ?categories p:category_name ?category_name .
} }
}
